INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'sl', 121, 1, NULL, 'Tomás de Aquino em Sl 121:1', 'Tomás de Aquino destaca a síntese entre fé, razão e vida santa. Em Salmos 121, o foco recai sobre adoração, sabedoria e temor do Senhor e chama a igreja para justiça com misericórdia. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Tomás de Aquino', 'commentary', '#6B4F2A', NOW()),
(gen_random_uuid(), 'sl', 122, 1, NULL, 'Thomas Goodwin em Sl 122:1', 'Thomas Goodwin interpreta este versículo a partir de a piedade prática e a santificação do coração. Em Salmos 122, Deus revela adoração, sabedoria e temor do Senhor de forma pastoral e transformadora, promovendo perseverança na tribulação. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Thomas Goodwin', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'sl', 123, 1, NULL, 'Alexander Maclaren em Sl 123:1', 'Alexander Maclaren destaca a coerência doutrinária aplicada à vida cristã. Em Salmos 123, o foco recai sobre adoração, sabedoria e temor do Senhor e chama a igreja para fidelidade na aliança. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Alexander Maclaren', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'sl', 124, 1, NULL, 'Basílio de Cesareia em Sl 124:1', 'Na leitura de Basílio de Cesareia, vemos a leitura cristológica e eclesial da passagem. Salmos 124 evidencia adoração, sabedoria e temor do Senhor como eixo da vida do povo de Deus, com ênfase em arrependimento sincero. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Basílio de Cesareia', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), 'sl', 125, 1, NULL, 'Stephen Charnock em Sl 125:1', 'Segundo Stephen Charnock, a piedade prática e a santificação do coração ilumina o sentido deste texto. Salmos 125 mostra que adoração, sabedoria e temor do Senhor sustenta a caminhada da fé, especialmente em esperança escatológica. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Stephen Charnock', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'sl', 126, 1, NULL, 'F. B. Meyer em Sl 126:1', 'Na leitura de F. B. Meyer, vemos a coerência doutrinária aplicada à vida cristã. Salmos 126 evidencia adoração, sabedoria e temor do Senhor como eixo da vida do povo de Deus, com ênfase em obediência da fé. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'F. B. Meyer', 'commentary', '#1D4ED8', NOW()),
